import { Component, effect, inject, input, signal } from '@angular/core';
import { Router } from '@angular/router';
import { CourseService } from '../../core/services/course.service';
import { ModuleItemDto } from '../../core/models/course.models';
import { adjacentItem, moduleItemRoute, navigableItems } from '../module-sequence';

/**
 * Canvas-style Previous / Next bar for sequential module progression.
 * Render it on any course item viewer (page, quiz, assignment) and pass the
 * module item id it was opened with; it fetches the course's ordered items and
 * navigates to the adjacent one. Middle content (e.g. "Mark as Complete") is
 * projected via <ng-content>.
 *
 *   <app-module-nav-bar [courseId]="id" [itemId]="itemId()">
 *     <button>Mark as Complete</button>
 *   </app-module-nav-bar>
 */
@Component({
  selector: 'app-module-nav-bar',
  standalone: true,
  template: `
    @if (itemId() !== null) {
      <div class="mnav">
        <div class="mnav-side mnav-left">
          @if (prev(); as pv) {
            <button class="btn btn-secondary" (click)="go(pv)" [title]="pv.displayTitle">
              <span class="material-icons" style="font-size:18px;">chevron_left</span> Previous
            </button>
          }
        </div>
        <div class="mnav-mid"><ng-content /></div>
        <div class="mnav-side mnav-right">
          @if (next(); as nx) {
            <button class="btn btn-primary" (click)="go(nx)" [title]="nx.displayTitle">
              Next <span class="material-icons" style="font-size:18px;">chevron_right</span>
            </button>
          }
        </div>
      </div>
    }
  `,
  styleUrl: './module-nav-bar.scss',
})
export class ModuleNavBarComponent {
  private cSvc = inject(CourseService);
  private router = inject(Router);

  readonly courseId = input.required<number>();
  readonly itemId = input<number | null>(null);

  readonly prev = signal<ModuleItemDto | null>(null);
  readonly next = signal<ModuleItemDto | null>(null);

  constructor() {
    // Recompute whenever the opened item changes (Next reuses the same viewer).
    effect(() => {
      const id = this.itemId();
      const courseId = this.courseId();
      this.prev.set(null);
      this.next.set(null);
      if (id === null) return;
      this.cSvc.getById(courseId).subscribe({
        next: course => {
          const items = navigableItems(course);
          this.prev.set(adjacentItem(items, id, -1));
          this.next.set(adjacentItem(items, id, 1));
        },
        error: () => { /* progression is best-effort */ },
      });
    });
  }

  go(item: ModuleItemDto): void {
    const t = moduleItemRoute(this.courseId(), item);
    this.router.navigate(t.link, { queryParams: t.query });
  }
}
